urlset:
{% for url_name in url_names %}  {{ domain }}{% url url_name %}
{% endfor %}{% for country_slug in country_slugs %}  {{ domain }}{% url 'country' country_slug %}
{% endfor %}{% for foodbank in foodbanks %}  {{ domain }}{% url 'wfbn-md:md_foodbank' foodbank.slug %}
{% endfor %}{% for location in locations %}  {{ domain }}{% url 'wfbn-md:md_foodbank_location' location.foodbank_slug location.slug %}
{% endfor %}{% for donationpoint in donationpoints %}  {{ domain }}{% url 'wfbn-md:md_foodbank_donationpoint' donationpoint.foodbank_slug donationpoint.slug %}
{% endfor %}{% for constituency in constituencies %}  {{ domain }}{% url 'wfbn:constituency' constituency.slug %}
{% endfor %}
